import { Resend } from "https://esm.sh/resend@2.0.0";
import { jsPDF } from "https://esm.sh/jspdf@2.5.2";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const resend = new Resend(Deno.env.get("RESEND_API_KEY"));

// Supabase Admin Client for reading settings
const supabaseAdmin = createClient(
  Deno.env.get("SUPABASE_URL")!,
  Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!
);

const FASCHING_LOGO = "data:image/jpeg;base64,";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

interface Material {
  id: string;
  material: string;
  menge: string | null;
  notizen: string | null;
}

interface Photo {
  id: string;
  file_path: string;
  file_name: string;
}

interface Disturbance {
  id: string;
  datum: string;
  start_time: string;
  end_time: string;
  pause_minutes: number;
  stunden: number;
  kunde_name: string;
  kunde_email: string | null;
  kunde_adresse: string | null;
  kunde_telefon: string | null;
  beschreibung: string;
  material_text?: string | null;
  notizen: string | null;
  unterschrift_kunde: string;
}

interface ReportRequest {
  disturbance: Disturbance;
  materials: Material[];
  technicianNames?: string[];
  technicianName?: string; // Legacy support
  photos?: Photo[];
}

function formatDate(dateStr: string): string {
  const date = new Date(dateStr);
  return date.toLocaleDateString("de-AT", {
    weekday: "long",
    day: "2-digit",
    month: "long",
    year: "numeric",
  });
}

function formatDateShort(dateStr: string): string {
  const date = new Date(dateStr);
  return date.toLocaleDateString("de-AT", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  });
}

async function fetchImageAsBase64(url: string): Promise<string | null> {
  try {
    const response = await fetch(url);
    if (!response.ok) {
      console.error("Failed to fetch image:", url, response.status);
      return null;
    }
    const arrayBuffer = await response.arrayBuffer();
    const uint8Array = new Uint8Array(arrayBuffer);
    let binary = "";
    for (let i = 0; i < uint8Array.length; i++) {
      binary += String.fromCharCode(uint8Array[i]);
    }
    const base64 = btoa(binary);
    const contentType = response.headers.get("content-type") || "image/jpeg";
    return `data:${contentType};base64,${base64}`;
  } catch (error) {
    console.error("Error fetching image:", error);
    return null;
  }
}

async function generatePDF(data: ReportRequest & { technicians: string[] }, photoImages: (string | null)[]): Promise<string> {
  const { disturbance, materials, technicians, photos } = data;
  const doc = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
  const pw = doc.internal.pageSize.getWidth();
  const ph = doc.internal.pageSize.getHeight();
  const m = 20;
  const cw = pw - 2 * m;
  let y = m;
  const text: [number,number,number] = [33, 33, 33];
  const label: [number,number,number] = [120, 120, 120];
  const line: [number,number,number] = [200, 200, 200];

  const footer = () => {
    doc.setDrawColor(...line);
    doc.setLineWidth(0.2);
    doc.line(m, ph - 15, m + cw, ph - 15);
    doc.setFontSize(7);
    doc.setTextColor(...label);
    doc.text("FASCHING Geb\u00e4udetechnik", m, ph - 11);
    const pg = (doc as any).internal.getCurrentPageInfo().pageNumber;
    doc.text("Seite " + pg, m + cw, ph - 11, { align: "right" });
  };

  const needPage = (h: number) => {
    if (y + h > ph - 20) { footer(); doc.addPage(); y = m; }
  };

  const section = (t: string) => {
    needPage(12);
    y += 4;
    doc.setFontSize(9);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(...text);
    doc.text(t, m, y);
    y += 1.5;
    doc.setDrawColor(...line);
    doc.setLineWidth(0.3);
    doc.line(m, y, m + cw, y);
    y += 5;
  };

  const row = (lbl: string, val: string, bold = false) => {
    needPage(5.5);
    doc.setFontSize(9);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(...label);
    doc.text(lbl, m, y);
    doc.setTextColor(...text);
    doc.setFont("helvetica", bold ? "bold" : "normal");
    doc.text(val, m + 35, y);
    y += 5.5;
  };

  // ── LOGO ──
  try {
    doc.addImage(FASCHING_LOGO, "JPEG", m, y, 65, 14);
  } catch (_) {
    doc.setFontSize(16);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(...text);
    doc.text("FASCHING Geb\u00e4udetechnik", m, y + 8);
  }

  doc.setFontSize(16);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(...text);
  doc.text("Arbeitsbericht", m + cw, y + 5, { align: "right" });
  doc.setFontSize(9);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(...label);
  doc.text(formatDate(disturbance.datum), m + cw, y + 11, { align: "right" });

  y += 18;
  doc.setDrawColor(...text);
  doc.setLineWidth(0.4);
  doc.line(m, y, m + cw, y);
  y += 8;

  // ── KUNDE ──
  section("Kunde");
  row("Name", disturbance.kunde_name, true);
  if (disturbance.kunde_adresse) row("Adresse", disturbance.kunde_adresse);
  y += 2;

  // ── EINSATZ ──
  section("Einsatzdaten");
  const st = disturbance.start_time.slice(0, 5);
  const et = disturbance.end_time.slice(0, 5);
  row("Datum", formatDate(disturbance.datum));
  row("Arbeitszeit", st + " \u2013 " + et + " Uhr");
  if (disturbance.pause_minutes > 0) row("Pause", disturbance.pause_minutes + " Min.");
  row("Stunden", disturbance.stunden.toFixed(2) + " h", true);
  if (technicians.length > 0) row("Techniker", technicians.join(", "));
  y += 2;

  // ── ARBEITEN ──
  section("Durchgef\u00fchrte Arbeiten");
  doc.setFontSize(9);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(...text);
  const lines = doc.splitTextToSize(disturbance.beschreibung, cw);
  for (const ln of lines) {
    needPage(5);
    doc.text(ln, m, y);
    y += 5;
  }
  y += 3;

  // ── MATERIAL ──
  // Vorrang: freies Material-Textfeld (neue Struktur), sonst Legacy-Tabelle
  const matText = (disturbance as any).material_text as string | null | undefined;
  if (matText && matText.trim()) {
    section("Verwendetes Material");
    doc.setFontSize(9);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(...text);
    const mLines = doc.splitTextToSize(matText.trim(), cw);
    for (const ln of mLines) {
      needPage(5);
      doc.text(ln, m, y);
      y += 5;
    }
    y += 3;
  } else if (materials && materials.length > 0) {
    section("Material");
    doc.setFillColor(240, 240, 240);
    doc.rect(m, y - 4, cw, 7, "F");
    doc.setFontSize(8);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(...text);
    doc.text("Bezeichnung", m + 3, y);
    doc.text("Menge", m + cw - 3, y, { align: "right" });
    y += 6;

    doc.setFont("helvetica", "normal");
    doc.setFontSize(9);
    materials.forEach((mat: any, i: number) => {
      needPage(6.5);
      if (i % 2 === 1) {
        doc.setFillColor(248, 248, 248);
        doc.rect(m, y - 4, cw, 6.5, "F");
      }
      doc.setTextColor(...text);
      doc.text(mat.material || "-", m + 3, y);
      doc.setTextColor(...label);
      doc.text(mat.menge || "-", m + cw - 3, y, { align: "right" });
      y += 6;
    });
    doc.setDrawColor(...line);
    doc.line(m, y - 2, m + cw, y - 2);
    y += 5;
  }

  // ── FOTOS ──
  if (photos && photos.length > 0 && photoImages.some((i: any) => i !== null)) {
    footer(); doc.addPage(); y = m;
    section("Fotos");
    for (let i = 0; i < photos.length; i++) {
      const img = photoImages[i];
      if (!img) continue;
      needPage(68);
      try {
        doc.setDrawColor(...line);
        doc.setLineWidth(0.2);
        doc.rect(m, y - 1, 82, 62, "S");
        doc.addImage(img, "JPEG", m + 1, y, 80, 60);
        y += 64;
        doc.setFontSize(7);
        doc.setTextColor(...label);
        doc.text(photos[i].file_name, m, y);
        y += 7;
      } catch (_e) {}
    }
  }

  // ── UNTERSCHRIFT ──
  needPage(50);
  section("Unterschrift");
  y += 2;
  if (disturbance.unterschrift_kunde) {
    try {
      doc.addImage(disturbance.unterschrift_kunde, "PNG", m, y, 55, 22);
      y += 26;
    } catch (_e) {
      doc.setFontSize(8); doc.setTextColor(...label);
      doc.text("[Unterschrift nicht verf\u00fcgbar]", m, y + 5);
      y += 12;
    }
  }
  doc.setDrawColor(...text);
  doc.setLineWidth(0.3);
  doc.line(m, y, m + 65, y);
  y += 4;
  doc.setFontSize(7);
  doc.setTextColor(...label);
  doc.text("Datum, Unterschrift Auftraggeber", m, y);
  y += 10;
  doc.setFontSize(7.5);
  doc.text("Hiermit wird die ordnungsgem\u00e4\u00dfe Durchf\u00fchrung der oben aufgef\u00fchrten Arbeiten best\u00e4tigt.", m, y);

  footer();
  return doc.output("datauristring").split(",")[1];
}

function generateEmailHtml(data: ReportRequest & { technicians: string[] }): string {
  const { disturbance, technicians } = data;
  const technicianDisplay = technicians.length === 1 ? technicians[0] : technicians.join(", ");
  
  return `
    <!DOCTYPE html>
    <html>
    <head>
      <meta charset="utf-8">
      <style>
        body { font-family: Arial, sans-serif; color: #333; line-height: 1.5; }
        .header { color: #b41c1c; font-size: 24px; font-weight: bold; margin-bottom: 10px; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; }
        .info-box { background: #f5f5f5; padding: 15px; border-radius: 8px; margin: 15px 0; }
      </style>
    </head>
    <body>
      <div class="container">
        <div class="header">FASCHING GEBÄUDETECHNIK</div>
        <h2>Arbeitsbericht</h2>
        
        <p>Sehr geehrte Damen und Herren,</p>
        
        <p>im Anhang finden Sie den Arbeitsbericht für den Einsatz bei <strong>${disturbance.kunde_name}</strong> vom <strong>${formatDate(disturbance.datum)}</strong>.</p>
        
        <div class="info-box">
          <strong>Zusammenfassung:</strong><br>
          Techniker: ${technicianDisplay}<br>
          Arbeitszeit: ${disturbance.start_time.slice(0, 5)} - ${disturbance.end_time.slice(0, 5)} Uhr<br>
          Gesamtstunden: ${disturbance.stunden.toFixed(2)} h
        </div>
        
        <p>Der vollständige Bericht mit allen Details und der Kundenunterschrift befindet sich im angehängten PDF-Dokument.</p>
        
        <p>Mit freundlichen Grüßen,<br>
        FASCHING Gebäudetechnik</p>
      </div>
    </body>
    </html>
  `;
}

Deno.serve(async (req: Request): Promise<Response> => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const { disturbance, materials, technicianNames, technicianName, photos }: ReportRequest = await req.json();

    // Backward compatibility + fallback
    const technicians = technicianNames?.length ? technicianNames : 
                        technicianName ? [technicianName] : ["Techniker"];

    if (!disturbance || !disturbance.unterschrift_kunde) {
      return new Response(
        JSON.stringify({ error: "Disturbance data and signature required" }),
        { status: 400, headers: { "Content-Type": "application/json", ...corsHeaders } }
      );
    }

    console.log("Generating PDF for disturbance:", disturbance.id);

    // Fetch photo images from storage
    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const photoImages: (string | null)[] = [];
    if (photos && photos.length > 0) {
      console.log(`Fetching ${photos.length} photos...`);
      for (const photo of photos) {
        const photoUrl = `${supabaseUrl}/storage/v1/object/public/disturbance-photos/${photo.file_path}`;
        const imageData = await fetchImageAsBase64(photoUrl);
        photoImages.push(imageData);
      }
    }

    // Generate PDF
    const pdfBase64 = await generatePDF({ disturbance, materials, technicians, photos }, photoImages);

    // Generate simple email HTML
    const emailHtml = generateEmailHtml({ disturbance, materials, technicians });

    // Fetch office email from settings with fallback
    const { data: setting } = await supabaseAdmin
      .from("app_settings")
      .select("value")
      .eq("key", "disturbance_report_email")
      .maybeSingle();

    const officeEmail = setting?.value || "office@fasching-gebaeudetechnik.at";
    console.log("Using office email:", officeEmail);

    // Prepare recipients - office email for all reports
    const recipients = [officeEmail];
    if (disturbance.kunde_email) {
      recipients.push(disturbance.kunde_email);
    }

    // Create filename
    const dateForFilename = formatDateShort(disturbance.datum).replace(/\./g, "-");
    const kundeForFilename = disturbance.kunde_name.replace(/[^a-zA-Z0-9äöüÄÖÜß]/g, "_");
    const pdfFilename = `Arbeitsbericht_${kundeForFilename}_${dateForFilename}.pdf`;

    const subject = `Arbeitsbericht - ${disturbance.kunde_name} - ${formatDateShort(disturbance.datum)}`;

    console.log("Sending email with PDF attachment to:", recipients);

    const emailResponse = await resend.emails.send({
      from: "FASCHING Gebäudetechnik <noreply@chrisnapetschnig.at>",
      to: recipients,
      subject: subject,
      html: emailHtml,
      attachments: [
        {
          filename: pdfFilename,
          content: pdfBase64,
        },
      ],
    });

    console.log("Email sent successfully:", emailResponse);

    // PDF in Projekt-Storage hochladen wenn Projekt zugeordnet
    if (disturbance.project_id) {
      try {
        const pdfBytes = Uint8Array.from(atob(pdfBase64), c => c.charCodeAt(0));
        const storagePath = `${disturbance.project_id}/${pdfFilename}`;
        const { error: uploadError } = await supabaseAdmin.storage
          .from("project-reports")
          .upload(storagePath, pdfBytes, {
            contentType: "application/pdf",
            upsert: true,
          });
        if (uploadError) {
          console.error("PDF upload to project storage failed:", uploadError);
        } else {
          console.log("PDF uploaded to project-reports:", storagePath);
        }
      } catch (uploadErr) {
        console.error("PDF upload error:", uploadErr);
      }
    }

    return new Response(
      JSON.stringify({ success: true, emailResponse }),
      { status: 200, headers: { "Content-Type": "application/json", ...corsHeaders } }
    );
  } catch (error: unknown) {
    console.error("Error sending disturbance report:", error);
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    return new Response(
      JSON.stringify({ error: errorMessage }),
      { status: 500, headers: { "Content-Type": "application/json", ...corsHeaders } }
    );
  }
});
